using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class MyTools
{
    [McpServerTool(Name = "echo"), Description("Echoes the input message back.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "add"), Description("Adds two numbers.")]
    public static string Add(double a, double b) => $"Result: {a + b}";
}

using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class MyResources
{
    [McpServerResource(UriTemplate = "config://app", Name = "app-config",
        Title = "Application Configuration", MimeType = "application/json")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new[] { "tools", "resources" }
        };
        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status", Name = "app-status",
        Title = "Server Status", MimeType = "application/json")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "Healthy",
            Uptime = Environment.TickCount64 / 1000,
            Timestamp = DateTimeOffset.UtcNow
        };
        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

